$(document).ready(function () {

    var baseUrl = window.location.origin;
    let retrive_data = baseUrl + '/ca_report_ako_karchu_ajax';

    let grandTotals = {
    Akki: 0,
    Kai: 0,
    Oil: 0
};

    var table = $('#ca-report-ako-karchu').DataTable({
        processing: true,
        serverSide: true,
        destroy: true,
        dom: 'Bfrtip',

        buttons: [
                // ✅ EXCEL EXPORT
                {
                    extend: 'excelHtml5',
                    text: 'Export to Excel',
                    filename: 'CA_Report_AKO_Karchu',

                    //For Full Excell Download Start
                    action: function (e, dt, button, config) {

                    var self = this;

                    dt.one('preXhr', function (e, s, data) {
                        data.length = -1; // ✅ fetch ALL records
                    });

                    dt.one('draw', function (e, settings) {
                        $.fn.dataTable.ext.buttons.excelHtml5.action.call(self, e, dt, button, config);
                    });

                    dt.ajax.reload();
                },
                // For Full Excell Downlaod Ends
                
                customize: function (xlsx) {
                    var sheet = xlsx.xl.worksheets['sheet1.xml'];

                    // Title
                    $('c[r=A1] t', sheet).text('AKO Karchu Report');
                    
                    // Last row
                    var lastRow = $('row', sheet).length + 1;

                    // ✅ Grand Total Row (Akki, Kai, Oil)
                    var grandTotalRow =
                        `<row r="${lastRow}">
                            <c t="inlineStr" s="2" r="A${lastRow}">
                                <is><t>Grand Total</t></is>
                            </c>
                            <c t="n" s="2" r="C${lastRow}">
                                <v>${grandTotals.Akki}</v>
                            </c>
                            <c t="n" s="2" r="D${lastRow}">
                                <v>${grandTotals.Kai}</v>
                            </c>
                            <c t="n" s="2" r="E${lastRow}">
                                <v>${grandTotals.Oil}</v>
                            </c>
                        </row>`;

                    sheet.childNodes[0].childNodes[1].innerHTML += grandTotalRow;
                }
            },

            // ✅ PDF EXPORT
            {
                extend: 'pdf',
                text: 'Export to PDF',
                filename: 'CA_Report_AKO_karchu',

                                //For Full PDF Data Downlaod Start
                action: function (e, dt, button, config) {

                    var self = this;

                    // 👉 Fetch ALL records from server
                    dt.one('preXhr', function (e, s, data) {
                        data.length = -1; // ✅ VERY IMPORTANT
                    });

                    dt.one('draw', function (e, settings) {

                        // 👉 Call original PDF export
                        $.fn.dataTable.ext.buttons.pdfHtml5.action.call(self, e, dt, button, config);

                        // 👉 Reload back normal table (10 rows)
                        dt.one('preXhr', function (e, s, data) {
                            data.length = 10; // or your page length
                        });

                        setTimeout(function () {
                            dt.ajax.reload();
                        }, 100);
                    });

                    dt.ajax.reload();
                },
                //For Full PDF Data Ends
                customize: function (doc) {

                        // ✅ Title (center)
                        doc.content.splice(0, 0, {
                            text: 'AKO Karchu Report',
                            fontSize: 14,
                            bold: true,
                            alignment: 'center', // 👈 center title
                            margin: [0, 0, 0, 10]
                        });

                        // ✅ Find table and center align it
                        var table = doc.content.find(item => item.table);

                        if (table) {
                            // 👉 SET COLUMN WIDTHS (important for center)
                        table.table.widths = ['auto', '*', 'auto', 'auto', 'auto'];

                        // 👉 CENTER TABLE USING MARGIN
                        table.margin = [60, 0, 60, 0];

                    // 👉 CENTER ALL DATA
                        table.table.body.forEach(function (row, i) {
                            if (i > 0) {
                                row.forEach(function (cell) {
                                    cell.alignment = 'left';
                                });
                            }
                        });

                        // 👉 OPTIONAL: BORDER STYLE
                        table.layout = {
                            hLineWidth: function () { return 0.5; },
                            vLineWidth: function () { return 0.5; },
                            hLineColor: function () { return '#aaa'; },
                            vLineColor: function () { return '#aaa'; },
                            paddingLeft: function () { return 8; },
                            paddingRight: function () { return 8; }
                        };
                    }

                        // ✅ Grand Total (center)
                        doc.content.push({
                            text: `Grand Total  |  Akki: ${grandTotals.Akki}  |  Kai: ${grandTotals.Kai}  |  Oil: ${grandTotals.Oil}`,
                            alignment: 'center', // 👈 center
                            margin: [0, 10, 0, 0],
                            bold: true
                        });
                    }
    }
        ],

        ajax: {
            url: retrive_data,
            data: function (d) {
                d.financial_year = $('.financial_year').val();
            },
            dataSrc: function (json) {
                 // ✅ store totals
                if (json.grand_total) {
                    grandTotals.Akki = json.grand_total.Akki;
                    grandTotals.Kai  = json.grand_total.Kai;
                    grandTotals.Oil  = json.grand_total.Oil;
                }

                return json.data;
            }
        },

        columns: [
            {
                data: null,
                render: function (data, type, row, meta) {
                    return meta.row + 1;
                }
            },
            { data: "subcategory_name" },
            { data: "Akki" },
            { data: "Kai" },
            { data: "Oil" },
            
        ],
         // ✅ ADD THIS
    footerCallback: function (row, data, start, end, display) {
        var api = this.api();

        // Get grand total from backend
        var json = api.ajax.json();

        if (json && json.grand_total) {
            $(api.column(2).footer()).html(json.grand_total.Akki);
            $(api.column(3).footer()).html(json.grand_total.Kai);
            $(api.column(4).footer()).html(json.grand_total.Oil);
        }
    }
    });

    // Reload on filter
    $('.submit_purchase_report').click(function () {
        table.ajax.reload();
    });

});